module parallel2serial(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);

parameter WIDTH = 4;
reg [WIDTH-1:0] shift_reg;
reg [2:0] counter;
reg valid;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        shift_reg <= 0;
        counter <= 0;
        valid <= 0;
    end else begin
        if (counter == 3) begin
            shift_reg <= d;
            counter <= 0;
            valid <= 1;
        end else begin
            shift_reg <= {shift_reg[WIDTH-2:0], 1'b0};
            counter <= counter + 1;
            valid <= 0;
        end
    end
end

assign valid_out = valid;
assign dout = shift_reg[WIDTH-1];

endmodule
